// 1 сервер → 10 серверов
// Load Balancer распределяет запросы
// Преимущества:
// - Нет единой точки отказа
// - Можно добавлять/убирать сервера динамически
// - Используем commodity hardware

// Auto-scaling (AWS/Azure/GCP)
// Добавляем инстансы при росте нагрузки
// Убираем при снижении (экономия)

// Nginx как Load Balancer
upstream backend {
  server backend1.example.com weight=5;
  server backend2.example.com;
  server backend3.example.com backup;

  least_conn; // алгоритм: наименее соединений
}

server {
  listen 80;
  location / {
    proxy_pass http://backend;

    // Health checks
    health_check interval=5s fails=3 passes=2;
  }
}

