// CAP Theorem в действии:

// CP система (Consistency + Partition tolerance)
// - MongoDB с write concern majority
// - PostgreSQL синхронная репликация
// - При разделении: отказываем в записи до восстановления
// Пример: банковская система - лучше недоступность, чем потеря денег

// AP система (Availability + Partition tolerance)
// - Cassandra, DynamoDB
// - DNS
// - При разделении: принимаем записи, разрешаем конфликты позже
// Пример: соцсеть - лучше показать старый пост, чем ошибку

// CA система (Consistency + Availability)
// - Невозможна в распределённой системе!
// - Только односерверные (не partition tolerant)

// Cache-Aside (самый популярный)
async function getUser(id) {
  // 1. Пробуем кэш
  let user = await redis.get(`user:${id}`);
  if (user) return JSON.parse(user);

  // 2. Промах - читаем из БД
  user = await db.users.findById(id);

  // 3. Пишем в кэш (TTL 1 час)
  await redis.setex(`user:${id}`, 3600, JSON.stringify(user));
  return user;
}

// Write-Through
async function updateUser(id, data) {
  await db.users.update(id, data);
  await redis.set(`user:${id}`, JSON.stringify(data));
}

// Cache Stampede защита (Per-Cache-Item Lock)
const user = await cache.getOrSet(`user:${id}`, () => {
  return db.users.findById(id); // выполнится только 1 раз
}, { lockTimeout: 5000 });

// CDN в архитектуре:
// User (Moscow) → Cloudflare Edge (Moscow) [10ms]
//                          ↓ cache miss
//                   Origin Server (Frankfurt) [150ms]

// Последующие запросы: 10ms вместо 150ms!

// Cloudflare Workers (Edge Computing)
addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  // Логика на edge-сервере, ближайшем к пользователю
  const country = request.headers.get('CF-IPCountry');

  if (country === 'RU') {
    return fetch('https://ru-origin.com' + request.url);
  }
  return fetch(request);
}

