// Master-Slave архитектура
// Write → Master (PostgreSQL)
// Read → Slaves (3 реплики)

// PostgreSQL настройка
// postgresql.conf на Master:
wal_level = replica
max_wal_senders = 3

// Connection string в приложении
const writePool = new Pool({ host: 'master.db', ... });
const readPool = new Pool({ host: 'replica.db', ... });

// Routing:
async function query(sql, params, type = 'read') {
  if (type === 'write') {
    return writePool.query(sql, params);
  }
  return readPool.query(sql, params);
}

// Replication Lag!
// После записи в Master данные могут появиться в Slave с задержкой
// Решение: 'sticky sessions' или читать из Master после записи

// Hash-based шардирование
function getShard(userId) {
  const shardCount = 4;
  return `shard_${userId % shardCount}`;
}

getShard(100); // shard_0
getShard(101); // shard_1

