// Token Bucket (Redis)
async function isAllowed(key, burst, rate) {
  const now = Date.now();
  const bucketKey = `ratelimit:${key}`;

  // Lua script для атомарности
  const lua = `
    local bucket = redis.call('HMGET', KEYS[1], 'tokens', 'last_update');
    local tokens = tonumber(bucket[1]) or ARGV[1];
    local last_update = tonumber(bucket[2]) or ARGV[2];
    local now = tonumber(ARGV[2]);

    local delta = math.max(0, now - last_update);
    tokens = math.min(ARGV[1], tokens + delta * ARGV[3]);

    if tokens >= 1 then
      tokens = tokens - 1;
      redis.call('HMSET', KEYS[1], 'tokens', tokens, 'last_update', now);
      redis.call('EXPIRE', KEYS[1], 60);
      return 1;
    else
      redis.call('HSET', KEYS[1], 'last_update', now);
      return 0;
    end
  `;

  return redis.eval(lua, 1, bucketKey, burst, now, rate);
}

// Использование: 100 запросов/минуту, burst 10
const allowed = await isAllowed(userId, 10, 100/60);

// Circuit Breaker реализация
class CircuitBreaker {
  constructor(threshold = 5, timeout = 60000) {
    this.failureCount = 0;
    this.threshold = threshold;
    this.timeout = timeout;
    this.state = 'CLOSED'; // CLOSED, OPEN, HALF_OPEN
    this.nextAttempt = Date.now();
  }

  async call(fn) {
    if (this.state === 'OPEN') {
      if (Date.now() < this.nextAttempt) {
        throw new Error('Circuit breaker is OPEN');
      }
      this.state = 'HALF_OPEN';
    }

    try {
      const result = await fn();
      this.onSuccess();
      return result;
    } catch (err) {
      this.onFailure();
      throw err;
    }
  }

  onSuccess() {
    this.failureCount = 0;
    this.state = 'CLOSED';
  }

  onFailure() {
    this.failureCount++;
    if (this.failureCount >= this.threshold) {
      this.state = 'OPEN';
      this.nextAttempt = Date.now() + this.timeout;
    }
  }
}

// Использование
const breaker = new CircuitBreaker(5, 60000);
const result = await breaker.call(() => fetchPaymentService());
